        return -0.5 * (y_train.T @ K_inv @ y_train + 2 * torch.logdet(K) + len(x_train) * np.log(2 * np.pi))
    elif Kinv_method == 'cholesky2':
        L = torch.linalg.cholesky(K)
        gamma = torch.cholesky_solve(y_train, L)
